package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testGetQuoteCharWhenQuoteCharIsNonNull() {
        Character quoteChar = '"';
        CSVFormat format = new CSVFormat(',', quoteChar, null, null, null,
                false, true, "\r\n", null, null, false);
        assertEquals(quoteChar, format.getQuoteChar());
    }

    @Test
    void testGetQuoteCharWhenQuoteCharIsNull() {
        CSVFormat format = new CSVFormat(',', null, null, null, null,
                false, true, "\r\n", null, null, false);
        assertNull(format.getQuoteChar());
    }
}
